/**
 * Megastructure Panel (G key — Grand Structures)
 *
 * Shows endgame construction projects: Orbital Platform and Dyson Swarm.
 * Displays stage costs, progress, drain status, crises, and construction controls.
 *
 * AST-30
 */

import {
  MEGASTRUCTURE_DEFS,
  CRISIS_DEFS,
  type MegastructureId,
  type MegastructureProjectSnapshot,
} from '../sim/megastructures';
import { safeHtml, trustedHtml } from './utils/safeHtml';

// ── State ─────────────────────────────────────────────────────────────────────

let panel: HTMLDivElement | null = null;
let visible = false;
let latestProjects: MegastructureProjectSnapshot[] = [];
let engineerCount = 0;
let latestRefined: Record<string, number> = {};

type StartStageCallback = (id: MegastructureId, stageIndex: number) => void;
type CrisisCallback = (id: MegastructureId) => void;

let onStartStage: StartStageCallback | null = null;
let onResolveCrisis: CrisisCallback | null = null;
let onSkipCrisis: CrisisCallback | null = null;

// ── Public API ────────────────────────────────────────────────────────────────

export interface MegastructurePanelCallbacks {
  onStartStage: StartStageCallback;
  onResolveCrisis: CrisisCallback;
  onSkipCrisis: CrisisCallback;
}

export function initMegastructurePanel(callbacks: MegastructurePanelCallbacks): void {
  onStartStage = callbacks.onStartStage;
  onResolveCrisis = callbacks.onResolveCrisis;
  onSkipCrisis = callbacks.onSkipCrisis;
}

export function updateMegastructurePanel(
  projects: MegastructureProjectSnapshot[],
  eng: number,
  refined: Record<string, number>,
): void {
  latestProjects = projects;
  engineerCount = eng;
  latestRefined = refined;
  if (visible) renderPanel();
}

export function toggleMegastructurePanel(): void {
  if (visible) hidePanel();
  else showPanel();
}

export function hideMegastructurePanel(): void {
  hidePanel();
}

// ── Panel lifecycle ───────────────────────────────────────────────────────────

function showPanel(): void {
  visible = true;
  if (!panel) buildPanel();
  renderPanel();
  panel!.style.display = 'flex';
}

function hidePanel(): void {
  visible = false;
  if (panel) panel.style.display = 'none';
}

function buildPanel(): void {
  panel = document.createElement('div');
  panel.style.cssText = `
    position: fixed;
    inset: 0;
    background: rgba(4,6,14,0.85);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 185;
    backdrop-filter: blur(4px);
  `;
  panel.addEventListener('click', (e) => {
    if (e.target === panel) hidePanel();
  });
  document.body.appendChild(panel);
}

// ── Rendering ─────────────────────────────────────────────────────────────────

function fmt(n: number): string {
  return n >= 1000 ? `${(n / 1000).toFixed(1)}k` : String(Math.round(n));
}

function ticksToTime(ticks: number): string {
  const secs = Math.ceil(ticks / 60);
  if (secs < 60) return `${secs}s`;
  const mins = Math.floor(secs / 60);
  const rem = secs % 60;
  return rem > 0 ? `${mins}m ${rem}s` : `${mins}m`;
}

function canAfford(cost: Partial<Record<string, number>>): boolean {
  for (const [res, qty] of Object.entries(cost)) {
    if ((latestRefined[res] ?? 0) < (qty ?? 0)) return false;
  }
  return true;
}

function renderCostLine(cost: Partial<Record<string, number>>): string {
  return Object.entries(cost)
    .map(([res, qty]) => {
      const have = latestRefined[res] ?? 0;
      const color = have >= (qty ?? 0) ? '#22c55e' : '#ef4444';
      const label = res.replace(/_/g, ' ');
      return `<span style="color:${color}">${fmt(qty ?? 0)} ${label} (${fmt(have)})</span>`;
    })
    .join(', ');
}

function renderDrainLine(drain: Partial<Record<string, number>>, intervalTicks: number): string {
  const intervalSecs = Math.round(intervalTicks / 60);
  const parts = Object.entries(drain).map(([res, qty]) => {
    const label = res.replace(/_/g, ' ');
    return `${fmt(qty ?? 0)} ${label}`;
  });
  return `${parts.join(' + ')} every ${intervalSecs}s`;
}

function appendCrisisCard(container: HTMLElement, proj: MegastructureProjectSnapshot): void {
  const crisis = proj.activeCrisis;
  if (!crisis) return;
  const crisisDef = CRISIS_DEFS[crisis.crisisId];
  if (!crisisDef) return;

  const isRepairing = !crisis.pending && (crisis.pauseTicksRemaining ?? 0) > 0;

  const card = document.createElement('div');
  card.style.cssText = `
    border: 1px solid ${isRepairing ? '#d97706' : '#dc2626'};
    border-radius: 6px;
    padding: 14px;
    margin-bottom: 10px;
    background: ${isRepairing ? 'rgba(120,53,15,0.2)' : 'rgba(127,29,29,0.25)'};
    ${isRepairing ? '' : 'animation: crisis-pulse 2s ease-in-out infinite;'}
  `;

  const title = document.createElement('div');
  title.style.cssText = `font-weight:bold;color:${isRepairing ? '#fbbf24' : '#f87171'};margin-bottom:6px;font-size:13px`;
  title.textContent = isRepairing
    ? `⟳ REPAIRS IN PROGRESS: ${crisisDef.name}`
    : `⚠ CRISIS: ${crisisDef.name}`;
  card.appendChild(title);

  if (isRepairing) {
    const pauseInfo = document.createElement('div');
    pauseInfo.style.cssText = 'color:#fde68a;font-size:12px;line-height:1.5';
    const secsRemaining = Math.ceil((crisis.pauseTicksRemaining ?? 0) / 60);
    pauseInfo.textContent = `Materials paid. Repair crews at work — construction resumes in ~${secsRemaining}s.`;
    card.appendChild(pauseInfo);
    container.appendChild(card);
    return;
  }

  const desc = document.createElement('div');
  desc.style.cssText = 'color:#fca5a5;font-size:12px;margin-bottom:10px;line-height:1.5';
  desc.textContent = crisisDef.description;
  card.appendChild(desc);

  const buttons = document.createElement('div');
  buttons.style.cssText = 'display:flex;gap:10px;flex-wrap:wrap';

  // Resolve button
  const resolveAffordable = canAfford(crisisDef.resolutionCost);
  const resolveBtn = document.createElement('button');
  resolveBtn.style.cssText = `
    padding: 6px 14px;
    background: ${resolveAffordable ? '#166534' : '#374151'};
    color: ${resolveAffordable ? '#86efac' : '#6b7280'};
    border: 1px solid ${resolveAffordable ? '#166534' : '#374151'};
    border-radius: 4px;
    font-size: 11px;
    cursor: ${resolveAffordable ? 'pointer' : 'not-allowed'};
    font-family: inherit;
  `;
  const resolveCostText = Object.entries(crisisDef.resolutionCost)
    .map(([r, q]) => `${fmt(q ?? 0)} ${r.replace(/_/g, ' ')}`)
    .join(' + ');
  resolveBtn.innerHTML = resolveAffordable
    ? safeHtml`✓ Resolve: pay ${resolveCostText}`
    : safeHtml`✗ Need ${resolveCostText}`;
  if (resolveAffordable && onResolveCrisis) {
    resolveBtn.onmouseover = () => (resolveBtn.style.background = '#15803d');
    resolveBtn.onmouseout = () => (resolveBtn.style.background = '#166534');
    resolveBtn.onclick = () => {
      if (onResolveCrisis) onResolveCrisis(proj.id);
    };
  }
  buttons.appendChild(resolveBtn);

  // Skip button (always available)
  const skipBtn = document.createElement('button');
  const penaltyPct = Math.round(crisisDef.progressPenalty * 100);
  skipBtn.style.cssText = `
    padding: 6px 14px;
    background: #7c2d12;
    color: #fdba74;
    border: 1px solid #7c2d12;
    border-radius: 4px;
    font-size: 11px;
    cursor: pointer;
    font-family: inherit;
  `;
  skipBtn.textContent = `⚡ Skip: lose ${penaltyPct}% progress`;
  skipBtn.onmouseover = () => (skipBtn.style.background = '#9a3412');
  skipBtn.onmouseout = () => (skipBtn.style.background = '#7c2d12');
  skipBtn.onclick = () => {
    if (onSkipCrisis) onSkipCrisis(proj.id);
  };
  buttons.appendChild(skipBtn);

  card.appendChild(buttons);
  container.appendChild(card);
}

function renderPanel(): void {
  if (!panel) return;
  panel.innerHTML = '';

  // Inject crisis pulse animation if not present
  if (!document.getElementById('mega-crisis-style')) {
    const style = document.createElement('style');
    style.id = 'mega-crisis-style';
    style.textContent = `
      @keyframes crisis-pulse {
        0%, 100% { border-color: #dc2626; }
        50% { border-color: #ef4444; box-shadow: 0 0 12px rgba(239,68,68,0.4); }
      }
    `;
    document.head.appendChild(style);
  }

  const container = document.createElement('div');
  container.style.cssText = `
    width: 720px;
    max-height: 85vh;
    overflow-y: auto;
    background: #080e1a;
    border: 1px solid #1e3a5f;
    border-radius: 8px;
    padding: 24px;
    color: #c8d8e8;
    font-family: 'Courier New', monospace;
    font-size: 13px;
  `;

  // Header
  const header = document.createElement('div');
  header.style.cssText = `
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
    border-bottom: 1px solid #1e3a5f;
    padding-bottom: 12px;
  `;
  header.innerHTML = safeHtml`
    <div>
      <div style="font-size:18px;font-weight:bold;color:#e2e8f0">⬡ MEGASTRUCTURES</div>
      <div style="color:#64748b;font-size:11px;margin-top:2px">Endgame construction — Engineer robots required</div>
    </div>
    <div style="text-align:right">
      <div style="color:#94a3b8">Engineers available</div>
      <div style="font-size:20px;font-weight:bold;color:${engineerCount > 0 ? '#22c55e' : '#ef4444'}">${engineerCount}</div>
    </div>
  `;
  const closeBtn = document.createElement('button');
  closeBtn.textContent = '✕';
  closeBtn.style.cssText = `
    background: none; border: none; color: #64748b; font-size: 18px;
    cursor: pointer; padding: 0 0 0 16px;
  `;
  closeBtn.onclick = hidePanel;
  header.appendChild(closeBtn);
  container.appendChild(header);

  // Render each megastructure
  for (const def of Object.values(MEGASTRUCTURE_DEFS)) {
    const proj = latestProjects.find((p) => p.id === def.id);
    const completedStages = proj?.completedStages ?? 0;
    const activeStageIndex = proj?.activeStageIndex ?? null;
    const isComplete = proj?.complete ?? false;

    // Check prerequisite
    let prereqMet = true;
    let prereqNote = '';
    if (def.prerequisite) {
      const prereqProj = latestProjects.find((p) => p.id === def.prerequisite!.id);
      const prereqCompleted = prereqProj?.completedStages ?? 0;
      if (prereqCompleted < def.prerequisite.minCompletedStages) {
        prereqMet = false;
        prereqNote = `Requires ${MEGASTRUCTURE_DEFS[def.prerequisite.id].name} fully complete`;
      }
    }

    const card = document.createElement('div');
    card.style.cssText = `
      border: 1px solid ${isComplete ? '#854d0e' : prereqMet ? '#1e3a5f' : '#1f2937'};
      border-radius: 6px;
      padding: 16px;
      margin-bottom: 16px;
      background: ${isComplete ? 'rgba(120,53,15,0.15)' : 'rgba(14,22,40,0.6)'};
    `;

    // Title bar
    const titleBar = document.createElement('div');
    titleBar.style.cssText =
      'display:flex;justify-content:space-between;align-items:center;margin-bottom:10px';
    titleBar.innerHTML = safeHtml`
      <div>
        <span style="font-size:15px;font-weight:bold;color:${isComplete ? '#fbbf24' : '#e2e8f0'}">${def.name}</span>
        ${isComplete ? ' <span style="color:#fbbf24;font-size:11px">✓ COMPLETE</span>' : ''}
        ${!prereqMet ? safeHtml` <span style="color:#6b7280;font-size:11px">(${prereqNote})</span>` : ''}
      </div>
      <div style="color:#64748b;font-size:11px">${completedStages}/${def.stages.length} stages</div>
    `;
    card.appendChild(titleBar);

    // Description
    const desc = document.createElement('div');
    desc.style.cssText = 'color:#64748b;font-size:11px;margin-bottom:12px';
    desc.textContent = def.description;
    card.appendChild(desc);

    // Crisis card (if active)
    if (proj?.activeCrisis) {
      appendCrisisCard(card, proj);
    }

    // Drain stall warning
    if (proj?.drainStalled) {
      const stallWarning = document.createElement('div');
      stallWarning.style.cssText = `
        border: 1px solid #d97706;
        border-radius: 4px;
        padding: 8px 12px;
        margin-bottom: 10px;
        background: rgba(120,53,15,0.2);
        color: #fbbf24;
        font-size: 12px;
      `;
      stallWarning.textContent =
        '⚠ STALLED — resource drain cannot be paid. Restock to resume construction.';
      card.appendChild(stallWarning);
    }

    // Stage list
    for (const stageDef of def.stages) {
      const stageCompleted = stageDef.index < completedStages;
      const stageActive = stageDef.index === activeStageIndex;
      const stageNext = stageDef.index === completedStages && !isComplete;

      const row = document.createElement('div');
      row.style.cssText = `
        padding: 8px 10px;
        margin-bottom: 6px;
        border-radius: 4px;
        border: 1px solid ${stageCompleted ? '#166534' : stageActive ? '#1d4ed8' : '#1f2937'};
        background: ${stageCompleted ? 'rgba(20,83,45,0.25)' : stageActive ? 'rgba(30,58,138,0.3)' : 'transparent'};
        opacity: ${stageNext || stageCompleted || stageActive ? '1' : '0.45'};
      `;

      // Stage header
      const stageHeader = document.createElement('div');
      stageHeader.style.cssText = 'display:flex;justify-content:space-between;align-items:center';
      stageHeader.innerHTML = safeHtml`
        <span style="color:${stageCompleted ? '#4ade80' : stageActive ? '#60a5fa' : '#94a3b8'}">
          ${stageCompleted ? '✓ ' : stageActive ? '⟳ ' : `${stageDef.index + 1}. `}
          <strong>${stageDef.name}</strong>
        </span>
        <span style="color:#64748b;font-size:11px">${ticksToTime(stageDef.baseTicks)} @ ${stageDef.engineersRequired} eng</span>
      `;
      row.appendChild(stageHeader);

      // Bonus
      const bonusEl = document.createElement('div');
      bonusEl.style.cssText = 'color:#a78bfa;font-size:11px;margin:3px 0';
      bonusEl.textContent = `Bonus: ${stageDef.bonus.description}`;
      row.appendChild(bonusEl);

      // Active drain warning for this stage (shown on upcoming/active stage)
      if ((stageNext || stageActive) && stageDef.activeDrain) {
        const drainEl = document.createElement('div');
        drainEl.style.cssText = 'color:#f59e0b;font-size:11px;margin:3px 0';
        const drainInterval = stageDef.drainIntervalTicks ?? 3600;
        drainEl.textContent = `⚡ Active drain: ${renderDrainLine(stageDef.activeDrain, drainInterval)} — keep refinery running`;
        row.appendChild(drainEl);
      }

      // Crisis type hint on upcoming/active stage
      if ((stageNext || stageActive) && stageDef.crisisType) {
        const crisisHint = document.createElement('div');
        crisisHint.style.cssText = 'color:#f87171;font-size:11px;margin:3px 0';
        crisisHint.textContent = `⚠ Crisis risk: ${CRISIS_DEFS[stageDef.crisisType]?.name ?? stageDef.crisisType}`;
        row.appendChild(crisisHint);
      }

      if (!stageCompleted) {
        // Cost
        const costEl = document.createElement('div');
        costEl.style.cssText = 'font-size:11px;margin-top:4px';
        costEl.innerHTML = safeHtml`Cost: ${trustedHtml(renderCostLine(stageDef.cost))}`;
        row.appendChild(costEl);
      }

      // Progress bar (active stage)
      if (stageActive && proj) {
        const pct = proj.stageProgressPct * 100;
        const isStalled = proj.drainStalled || proj.activeCrisis !== null || engineerCount === 0;
        const etaText = isStalled
          ? ' — STALLED'
          : proj.estimatedTicksRemaining !== null
            ? ` — ETA ${ticksToTime(proj.estimatedTicksRemaining)}`
            : '';

        const progressWrap = document.createElement('div');
        progressWrap.style.cssText = 'margin-top:8px';
        progressWrap.innerHTML = safeHtml`
          <div style="display:flex;justify-content:space-between;font-size:11px;color:#94a3b8;margin-bottom:4px">
            <span>Construction progress${etaText}</span>
            <span>${pct.toFixed(1)}%</span>
          </div>
          <div style="background:#1f2937;border-radius:3px;height:8px;overflow:hidden">
            <div style="width:${pct.toFixed(1)}%;height:100%;background:${isStalled ? 'linear-gradient(90deg,#92400e,#d97706)' : 'linear-gradient(90deg,#1d4ed8,#3b82f6)'};border-radius:3px;transition:width 0.5s"></div>
          </div>
        `;
        row.appendChild(progressWrap);

        // Crisis countdown warning
        if (proj.crisisCountdownTicksRemaining != null && proj.crisisCountdownTicksRemaining > 0) {
          const urgent = proj.crisisCountdownTicksRemaining <= 5;
          const countdownWarn = document.createElement('div');
          countdownWarn.style.cssText = `
            border: 1px solid ${urgent ? '#fbbf24' : '#ef4444'};
            border-radius: 4px;
            padding: 8px 12px;
            margin-top: 8px;
            background: ${urgent ? 'rgba(120,53,15,0.3)' : 'rgba(127,29,29,0.3)'};
            color: ${urgent ? '#fbbf24' : '#f87171'};
            font-size: 12px;
            font-weight: bold;
            ${urgent ? 'animation: mega-crisis-pulse 0.4s ease-in-out infinite;' : 'animation: mega-crisis-pulse 1.2s ease-in-out infinite;'}
          `;
          countdownWarn.textContent =
            `⚠ STAGE CRISIS — ${proj.crisisCountdownTicksRemaining} ticks until stage is lost!`;
          row.appendChild(countdownWarn);
        }

        // Drain accumulator hint
        if (proj.hasDrain && proj.drainIntervalTicks !== null) {
          const drainPct = (proj.drainAccumulator / proj.drainIntervalTicks) * 100;
          const nextDrainEl = document.createElement('div');
          nextDrainEl.style.cssText = 'margin-top:4px';
          nextDrainEl.innerHTML = safeHtml`
            <div style="font-size:10px;color:#64748b;margin-bottom:2px">Next drain in ${ticksToTime(proj.drainIntervalTicks - proj.drainAccumulator)}</div>
            <div style="background:#1f2937;border-radius:2px;height:3px;overflow:hidden">
              <div style="width:${drainPct.toFixed(1)}%;height:100%;background:#f59e0b;border-radius:2px"></div>
            </div>
          `;
          row.appendChild(nextDrainEl);
        }
      }

      // Start button (next stage only, not active, prereq met)
      if (stageNext && !stageActive && prereqMet) {
        const affordable = canAfford(stageDef.cost);
        const btn = document.createElement('button');
        btn.style.cssText = `
          margin-top: 8px;
          padding: 5px 14px;
          background: ${affordable ? '#1d4ed8' : '#374151'};
          color: ${affordable ? '#e2e8f0' : '#6b7280'};
          border: none;
          border-radius: 4px;
          font-size: 12px;
          cursor: ${affordable ? 'pointer' : 'not-allowed'};
          font-family: inherit;
        `;
        btn.disabled = !affordable;
        btn.textContent = affordable
          ? `▶ Begin Stage ${stageDef.index + 1}: ${stageDef.name}`
          : `✗ Insufficient resources`;
        if (affordable) {
          btn.onmouseover = () => (btn.style.background = '#2563eb');
          btn.onmouseout = () => (btn.style.background = '#1d4ed8');
          btn.onclick = () => {
            if (onStartStage) onStartStage(def.id, stageDef.index);
          };
        }
        row.appendChild(btn);
      }

      card.appendChild(row);
    }

    container.appendChild(card);
  }

  // Footer note
  const footer = document.createElement('div');
  footer.style.cssText = 'text-align:center;color:#374151;font-size:11px;margin-top:8px';
  footer.textContent =
    '[G] to close  ·  Requires Engineer robots in fleet  ·  Active drain stages require sustained supply';
  container.appendChild(footer);

  panel.appendChild(container);
}
